+		{IssueStatusPinned, false},
+		{StatusInProgress, false},
+		{StatusTombstone, false},
+	}
+	for _, tt := range tests {
+		if got := tt.status.BlocksRemoval(); got != tt.want {
+			t.Errorf("IssueStatus(%q).BlocksRemoval() = %v, want %v", tt.status, got, tt.want)
+		}
+	}
+}
+
